function estAutorise(role: Role): boolean {
  return role === Role.ADMIN || role === Role.UTILISATEUR;
}

enum CategorieProduit {
  ELECTRONIQUE = 'ELEC',
  VETEMENTS = 'VET',
  ALIMENTATION = 'ALIM',
  LIBRAIRIE = 'LIVRE'
}

sousQuestions.reponse:
const labels: Record<CategorieProduit, string> = {
  [CategorieProduit.ELECTRONIQUE]: 'Électronique',
  [CategorieProduit.VETEMENTS]: 'Vêtements',
  [CategorieProduit.ALIMENTATION]: 'Alimentation',
  [CategorieProduit.LIBRAIRIE]: 'Librairie'
};

function getCategorieLabel(categorie: CategorieProduit): string {
  return labels[categorie] ?? 'Inconnu';
}
